import{_ as n,o as a,c as e,ag as i}from"./chunks/framework.BbyMWZAR.js";const m=JSON.parse('{"title":"npm / yarn / pnpm 包管理器对比","description":"","frontmatter":{"title":"npm / yarn / pnpm 包管理器对比","difficulty":"medium","tags":["npm","yarn","pnpm","包管理","monorepo"],"estimate":20},"headers":[],"relativePath":"domains/nodejs/qa/qa-12-package-managers.md","filePath":"domains/nodejs/qa/qa-12-package-managers.md","lastUpdated":1783504823000}'),l={name:"domains/nodejs/qa/qa-12-package-managers.md"};function p(o,s,r,t,d,c){return a(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="问答-12-进阶-npm-yarn-pnpm-包管理器对比" tabindex="-1">问答 12（进阶）：npm / yarn / pnpm 包管理器对比 <a class="header-anchor" href="#问答-12-进阶-npm-yarn-pnpm-包管理器对比" aria-label="Permalink to &quot;问答 12（进阶）：npm / yarn / pnpm 包管理器对比&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请对比 npm、Yarn、pnpm 三款包管理器的核心差异。它们的依赖安装方式有什么不同？什么是幽灵依赖问题？pnpm 的 store 机制是怎么回事？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>三者出现的背景</strong></p><ul><li><strong>npm v1/v2</strong>：最早的包管理器，采用<strong>嵌套结构</strong>，每个包有自己的 <code>node_modules</code>，层级深、重复安装多、Windows 路径过长问题。</li><li><strong>Yarn（2016）</strong>：Facebook 推出，解决了早期 npm 的几个痛点：确定性安装（yarn.lock）、并行下载、缓存、离线安装。推动了 npm v5 的改进（package-lock.json）。</li><li><strong>pnpm（2017）</strong>：Zoltan Kochan 推出，用<strong>硬链接 + 符号链接</strong>的方式解决磁盘占用和幽灵依赖问题，安装速度极快，天然支持 monorepo。</li><li><strong>npm v3+</strong>：后来也采用了扁平化结构，和 Yarn Classic 类似。</li></ul><p><strong>依赖安装方式差异</strong></p><table tabindex="0"><thead><tr><th>特性</th><th>npm v3+/Yarn Classic</th><th>pnpm</th></tr></thead><tbody><tr><td>目录结构</td><td>扁平化（hoist）</td><td>半严格 + symlink</td></tr><tr><td>幽灵依赖</td><td>有</td><td>默认无</td></tr><tr><td>磁盘占用</td><td>高（每个项目一份）</td><td>极低（全局 store 硬链接）</td></tr><tr><td>安装速度</td><td>中等</td><td>快 2-3 倍</td></tr><tr><td>确定性</td><td>lockfile 保证</td><td>lockfile 保证</td></tr><tr><td>monorepo 支持</td><td>需 workspaces</td><td>内置，一等公民</td></tr></tbody></table><p><strong>npm / Yarn Classic 的扁平化（hoisting）</strong></p><p>安装时把所有依赖及其子依赖尽量提升到根 <code>node_modules</code> 下，减少重复。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_modules/</span></span>
<span class="line"><span>├── lodash/         ← 提升到根</span></span>
<span class="line"><span>├── axios/</span></span>
<span class="line"><span>│   └── node_modules/...（版本冲突的才嵌套）</span></span>
<span class="line"><span>└── express/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>优点：减少重复安装，路径不会过长。 缺点：<strong>幽灵依赖</strong>——你的代码可以 <code>require(&#39;lodash&#39;)</code>，即使 <code>package.json</code> 里没声明它（因为它是某个依赖的依赖，被提升了）。</p><p><strong>pnpm 的目录结构</strong></p><p>pnpm 用「内容寻址存储 + 符号链接」实现：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_modules/</span></span>
<span class="line"><span>├── .pnpm/               ← 虚拟存储，所有包的真实位置（硬链接到全局 store）</span></span>
<span class="line"><span>│   ├── lodash@4.17.21/</span></span>
<span class="line"><span>│   │   └── node_modules/lodash → ../../../../&lt;store&gt;/...</span></span>
<span class="line"><span>│   └── axios@1.6.0/</span></span>
<span class="line"><span>│       └── node_modules/</span></span>
<span class="line"><span>│           ├── axios → ../../../../&lt;store&gt;/...</span></span>
<span class="line"><span>│           └── follow-redirects → ../../follow-redirects@1.15.0/...</span></span>
<span class="line"><span>├── axios → .pnpm/axios@1.6.0/node_modules/axios   ← 根目录的直接依赖</span></span>
<span class="line"><span>└── express → .pnpm/express@4.18.2/node_modules/express</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>特点：</p><ul><li>根 <code>node_modules</code> 里只有你在 <code>package.json</code> 里声明的包（通过 symlink 指向 <code>.pnpm</code> 里的对应版本）。</li><li>每个包的依赖都在它自己的 <code>node_modules</code> 里（也是 symlink）。</li><li><strong>真实文件只在全局 store 存一份</strong>，项目里都是硬链接和符号链接。</li></ul><p><strong>pnpm 的 store 机制</strong></p><ul><li>全局内容寻址存储（content-addressable store），默认在 <code>~/.local/share/pnpm/store</code>（不同 OS 路径不同）。</li><li>每个版本的每个包在 store 里<strong>只存一份</strong>。</li><li>项目通过<strong>硬链接</strong>（hard link）引用 store 里的文件。硬链接的好处是：删除项目不会影响 store，多个项目共享同一份文件，极大节省磁盘空间。</li><li>内容寻址意味着：相同内容的文件只存一次（即使是不同包的相同文件）。</li><li>可以用 <code>pnpm store path</code> 查看 store 位置，<code>pnpm store prune</code> 清理未被引用的包。</li></ul><p><strong>幽灵依赖（Phantom Dependencies）问题</strong></p><p>定义：代码里引用了 <code>package.json</code> 中没有声明的包，但由于被其他依赖间接安装（hoist 提升），所以能用。</p><p>为什么是问题：</p><ol><li><strong>不可靠</strong>：某个依赖升级后可能不再依赖它，你的代码就突然报错了。</li><li><strong>版本不确定</strong>：如果多个依赖都依赖同一个包但版本不同，提升哪个取决于安装顺序和算法，可能不一致。</li><li><strong>不利于维护</strong>：别人 clone 你的项目可能因为 lockfile 差异而行为不同。</li></ol><p>pnpm 默认通过严格的 <code>node_modules</code> 结构解决了这个问题——根目录只有显式声明的包。如果需要兼容某些依赖间接引用的场景，可以用 <code>pnpm.hoist-pattern</code> 配置提升特定包。</p><p><strong>lockfile 差异</strong></p><ul><li><strong>npm</strong>：<code>package-lock.json</code>（v1/v2/v3 格式演进）。</li><li><strong>Yarn Classic (v1)</strong>：<code>yarn.lock</code>。</li><li><strong>Yarn Berry (v2+/Berry)</strong>：<code>yarn.lock</code>，格式不同，支持 Zero-Installs（把 <code>.yarn/cache</code> 提交到 git）。</li><li><strong>pnpm</strong>：<code>pnpm-lock.yaml</code>，更紧凑、更易读，记录了完整的依赖图和 hash。</li></ul><p><strong>安装速度与磁盘占用</strong></p><ul><li>速度：pnpm &gt; Yarn &gt; npm（粗略）。pnpm 快的原因：全局 store 减少重复下载、硬链接比复制快、并行度高。</li><li>磁盘：pnpm 优势巨大。10 个相似项目，npm 可能占 10 份空间，pnpm 基本只占 1 份多一点。</li></ul><p><strong>monorepo 支持</strong></p><ul><li>npm / Yarn：有 workspaces 功能，但比较基础。</li><li>pnpm：内置且强大，workspace 协议（<code>workspace:*</code>）、过滤（<code>--filter</code>）、增量构建等都是一等公民，是 monorepo 场景的热门选择。</li></ul><h2 id="追问-1-什么是「依赖提升-hoisting-算法」-为什么会有版本冲突-npm-是怎么决定提升哪个版本的" tabindex="-1">追问 1：什么是「依赖提升（hoisting）算法」？为什么会有版本冲突？npm 是怎么决定提升哪个版本的？ <a class="header-anchor" href="#追问-1-什么是「依赖提升-hoisting-算法」-为什么会有版本冲突-npm-是怎么决定提升哪个版本的" aria-label="Permalink to &quot;追问 1：什么是「依赖提升（hoisting）算法」？为什么会有版本冲突？npm 是怎么决定提升哪个版本的？&quot;">​</a></h2><h3 id="答" tabindex="-1">答 <a class="header-anchor" href="#答" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>hoisting 的目标是把依赖树尽量拍平，减少重复安装。</p><p><strong>算法大致逻辑</strong>：</p><ol><li>先构建完整的依赖树，每个节点是「包名 + 版本」。</li><li>从根开始，按某种顺序（通常是字母序或解析顺序）遍历，遇到一个包就看看根 <code>node_modules</code> 里有没有同名的。</li><li>如果没有，就提升到根。</li><li>如果已有且版本兼容（满足 semver），就复用。</li><li>如果已有但版本不兼容，就留在原处（嵌套）。</li></ol><p><strong>为什么会有版本冲突</strong>： 比如 A 依赖 <code>lodash@^4.17.0</code>，B 依赖 <code>lodash@3.x</code>，这两个 semver 范围不重叠，只能提升一个，另一个必须嵌套。</p><p><strong>决定提升哪个版本</strong>：</p><ul><li>取决于<strong>遍历顺序</strong>。npm 的算法大致是「先到先得」——先被解析到的版本被提升。</li><li>这也是为什么早期 npm 没有 lockfile 时，不同机器、不同安装顺序可能得到不同的依赖树（非确定性）。lockfile 就是为了固化这个结果。</li><li>即使有 lockfile，当你新增/删除依赖时，提升结果也可能变化，所以要谨慎对待间接依赖的使用。</li></ul><h2 id="追问-2-pnpm-的「严格模式」具体严格在哪里-如果项目依赖的包有幽灵依赖问题-自己-import-了没声明的依赖-在-pnpm-下跑不起来怎么办" tabindex="-1">追问 2：pnpm 的「严格模式」具体严格在哪里？如果项目依赖的包有幽灵依赖问题（自己 import 了没声明的依赖），在 pnpm 下跑不起来怎么办？ <a class="header-anchor" href="#追问-2-pnpm-的「严格模式」具体严格在哪里-如果项目依赖的包有幽灵依赖问题-自己-import-了没声明的依赖-在-pnpm-下跑不起来怎么办" aria-label="Permalink to &quot;追问 2：pnpm 的「严格模式」具体严格在哪里？如果项目依赖的包有幽灵依赖问题（自己 import 了没声明的依赖），在 pnpm 下跑不起来怎么办？&quot;">​</a></h2><h3 id="答-1" tabindex="-1">答 <a class="header-anchor" href="#答-1" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>pnpm 的严格体现在：<strong>根 <code>node_modules</code> 里只有 <code>package.json</code> 显式声明的依赖</strong>。任何包想访问自己没声明的依赖，默认都会失败。</p><p>如果遇到跑不起来的情况：</p><ol><li><p><strong>是自己的代码用了幽灵依赖</strong>：</p><ul><li>正确做法：在 <code>package.json</code> 里补上这个依赖。这也是 pnpm 推荐的方式。</li></ul></li><li><p><strong>是第三方包有幽灵依赖问题</strong>（即某个依赖 A 偷偷用了依赖 B 但 A 没声明 B）：</p><ul><li>用 <code>.npmrc</code> 里的 <code>public-hoist-pattern[]</code> 或 <code>hoist-pattern[]</code> 配置，把特定的包提升到根 <code>node_modules</code>。</li><li>例：<code>public-hoist-pattern[]=eslint*</code> 把 eslint 相关的都提升。</li><li>极端情况：<code>shamefully-hoist=true</code>，完全扁平化，和 npm 一样（不推荐，但可作为迁移过渡方案）。</li></ul></li><li><p><strong>用 <code>.pnpmfile.cjs</code> (hooks)</strong>：</p><ul><li>通过 <code>readPackage</code> hook 修改依赖的 <code>package.json</code>，给它补上缺失的依赖声明。这是最干净的修复方式。</li></ul></li></ol><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// .pnpmfile.cjs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> readPackage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">pkg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (pkg.name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;some-bad-package&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pkg.dependencies </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pkg.dependencies </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">||</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {};</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pkg.dependencies[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;missing-dep&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^1.0.0&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pkg;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exports</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { hooks: { readPackage } };</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="追问-3-什么是-yarn-berry-v2-的-pnp-plug-n-play-模式-它和传统-node-modules-有什么本质区别" tabindex="-1">追问 3：什么是 Yarn Berry（v2+）的 PnP（Plug&#39;n&#39;Play）模式？它和传统 node_modules 有什么本质区别？ <a class="header-anchor" href="#追问-3-什么是-yarn-berry-v2-的-pnp-plug-n-play-模式-它和传统-node-modules-有什么本质区别" aria-label="Permalink to &quot;追问 3：什么是 Yarn Berry（v2+）的 PnP（Plug&#39;n&#39;Play）模式？它和传统 node_modules 有什么本质区别？&quot;">​</a></h2><h3 id="答-2" tabindex="-1">答 <a class="header-anchor" href="#答-2" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>PnP 是 Yarn Berry 推出的一种<strong>无 <code>node_modules</code></strong> 的依赖管理方案。</p><p><strong>传统 node_modules 的问题</strong>：</p><ul><li>安装时要创建大量文件和目录，慢。</li><li>Node 解析模块时要遍历很多 <code>node_modules</code> 目录（<code>require</code> 路径解析算法），启动慢。</li><li>结构不稳定，幽灵依赖问题。</li></ul><p><strong>PnP 的做法</strong>：</p><ol><li>不生成 <code>node_modules</code> 目录。</li><li>所有包以 zip 形式存在 <code>.yarn/cache/</code> 里。</li><li>生成一个 <code>.pnp.cjs</code> 文件，里面有一张<strong>完整的依赖映射表</strong>：每个包的位置、它的依赖指向哪个版本。</li><li>通过 Node 的 <code>--require</code> 钩子，拦截 <code>require</code> 和 <code>import</code>，直接从映射表和 zip 里找模块，跳过了文件系统遍历。</li></ol><p><strong>优点</strong>：</p><ul><li>安装极快（主要是下载和解压 zip）。</li><li>启动更快（无需遍历目录）。</li><li>完全确定，没有幽灵依赖。</li><li>可以 Zero-Installs：把 <code>.yarn/cache</code> 和 <code>.pnp.cjs</code> 提交到 git，新成员 clone 下来直接跑，不用 install。</li></ul><p><strong>缺点</strong>：</p><ul><li>生态兼容性问题：有些工具（如 IDE、打包器、CLI 工具）默认假设 <code>node_modules</code> 存在，需要额外适配。</li><li>调试时看源码不方便（在 zip 里）。</li><li>社区普及度不如 pnpm。</li></ul><p>pnpm 的 hard link + symlink 方案可以看作「传统 node_modules 模型」和「PnP 模型」之间的折中——保留了 node_modules 结构（兼容性好），又通过全局 store 节省了空间和时间。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://docs.npmjs.com/" target="_blank" rel="noreferrer">npm Docs</a>：lockfile、semver、workspaces 与幽灵依赖背景。</li><li><a href="https://pnpm.io/motivation" target="_blank" rel="noreferrer">pnpm: Motivation</a>：内容寻址 store 与 symlink 结构，对比 npm/Yarn 扁平化。</li><li><a href="https://nodejs.org/api/packages.html" target="_blank" rel="noreferrer">Node.js: Packages</a>：<code>package.json</code> 字段、<code>exports</code> 与模块解析在 Node 侧的约定。</li></ul>`,59)])])}const g=n(l,[["render",p]]);export{m as __pageData,g as default};
